import React from "react";
import { motion, type Variants } from "framer-motion";

type ServiceCard = {
  title: string;
  highlight: string;
  bullets: string[];
};

type DeliveryModel = {
  title: string;
  subtitle: string;
  icon: React.ReactNode;
};

const Dot = () => (
  <span className="mt-2 h-1.5 w-1.5 shrink-0 rounded-full bg-red-500" />
);

function ServiceCardItem({ card }: Readonly<{ card: ServiceCard }>) {
  const container: Variants = {
    hidden: { opacity: 0, y: 30 },
    visible: {
      opacity: 1,
      y: 0,
      transition: {
        duration: 0.5,
        ease: "easeOut",
        staggerChildren: 0.08,
      },
    },
  };

  const item: Variants = {
    hidden: { opacity: 0, y: 15 },
    visible: {
      opacity: 1,
      y: 0,
      transition: { duration: 0.4 },
    },
  };

  return (
    <motion.div
      variants={container}
      initial="hidden"
      whileInView="visible"
      viewport={{ once: true, amount: 0.3 }}
      whileHover={{ y: -6 }}
      transition={{ duration: 0.25 }}
      className="p-5 bg-white rounded-xl border border-gray-200 shadow-sm transition-all duration-300 hover:shadow-md"
    >
      <motion.h3 variants={item} className="text-xl font-bold text-gray-900">
        {card.title}
      </motion.h3>

      <motion.p
        variants={item}
        className="mt-2 text-xs font-semibold text-red-600"
      >
        {card.highlight}
      </motion.p>

      <motion.ul variants={container} className="mt-3 space-y-2">
        {card.bullets.map((b) => (
          <motion.li
            key={b}
            variants={item}
            className="flex gap-2 text-xs leading-relaxed text-gray-600"
          >
            <Dot />
            <span>{b}</span>
          </motion.li>
        ))}
      </motion.ul>
    </motion.div>
  );
}

